CREATE TABLE sqlite_sequence(name,seq);
CREATE TABLE `Patients` (`id` UUID UNIQUE PRIMARY KEY, `firstName` VARCHAR(255) NOT NULL, `lastName` VARCHAR(255) NOT NULL, `docNumber` VARCHAR(255) NOT NULL UNIQUE, `email` VARCHAR(255), `phone` VARCHAR(255), `createdAt` DATETIME NOT NULL, `updatedAt` DATETIME NOT NULL, `docTypeId` UUID REFERENCES `DocumentTypes` (`id`) ON DELETE SET NULL ON UPDATE CASCADE, `isInactive` TINYINT(1) DEFAULT 0, `street` VARCHAR(255), `number` VARCHAR(255), `floor` VARCHAR(255), `apartment` VARCHAR(255), `province` VARCHAR(255), `city` VARCHAR(255), `postalCode` VARCHAR(255), `birthDate` DATE);
CREATE TABLE `Appointments` (`id` UUID UNIQUE PRIMARY KEY, `startTime` DATETIME NOT NULL, `endTime` DATETIME NOT NULL, `status` TEXT DEFAULT 'scheduled', `notes` TEXT, `createdAt` DATETIME NOT NULL, `updatedAt` DATETIME NOT NULL, `patientId` UUID REFERENCES `Patients` (`id`), `professionalId` UUID REFERENCES `Professionals` (`id`), `benefitId` UUID REFERENCES `Prestaciones` (`id`) ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE `ProfessionalBenefits` (`id` INTEGER PRIMARY KEY, `ProfessionalId` UUID NOT NULL REFERENCES `Professionals` (`id`), `BenefitId` UUID NOT NULL REFERENCES `Prestaciones` (`id`), `createdAt` DATETIME NOT NULL, `updatedAt` DATETIME NOT NULL);
CREATE TABLE `Activities` (`id` UUID UNIQUE PRIMARY KEY, `description` TEXT NOT NULL, `date` DATETIME, `createdAt` DATETIME NOT NULL, `updatedAt` DATETIME NOT NULL, `patientId` UUID REFERENCES `Patients` (`id`), `professionalId` UUID REFERENCES `Professionals` (`id`) ON DELETE SET NULL ON UPDATE CASCADE);
CREATE TABLE `Patients_backup` (`id` UUID UNIQUE PRIMARY KEY, `firstName` VARCHAR(255) NOT NULL, `lastName` VARCHAR(255) NOT NULL, `docNumber` VARCHAR(255) NOT NULL UNIQUE, `email` VARCHAR(255), `phone` VARCHAR(255), `address` VARCHAR(255), `createdAt` DATETIME NOT NULL, `updatedAt` DATETIME NOT NULL, `docTypeId` UUID REFERENCES `DocumentTypes` (`id`), `isInactive` TINYINT(1) DEFAULT 0, `street` VARCHAR(255), `number` VARCHAR(255), `floor` VARCHAR(255), `apartment` VARCHAR(255), `province` VARCHAR(255), `city` VARCHAR(255), `postalCode` VARCHAR(255));
CREATE TABLE `PatientDocuments` (`id` UUID PRIMARY KEY, `patientId` UUID NOT NULL REFERENCES `Patients` (`id`) ON DELETE CASCADE ON UPDATE CASCADE, `originalName` VARCHAR(255) NOT NULL, `url` VARCHAR(255) NOT NULL, `mimetype` VARCHAR(255), `size` INTEGER, `createdAt` DATETIME NOT NULL, `updatedAt` DATETIME NOT NULL);
CREATE TABLE `Prestaciones` (`id` UUID UNIQUE PRIMARY KEY, `name` VARCHAR(255) NOT NULL, `description` TEXT, `createdAt` DATETIME NOT NULL, `updatedAt` DATETIME NOT NULL);
CREATE TABLE `DocumentTypes` (`id` UUID UNIQUE PRIMARY KEY, `name` VARCHAR(255) NOT NULL UNIQUE, `createdAt` DATETIME NOT NULL, `updatedAt` DATETIME NOT NULL);
CREATE TABLE `Professionals` (`id` UUID UNIQUE PRIMARY KEY, `firstName` VARCHAR(255) NOT NULL, `lastName` VARCHAR(255) NOT NULL, `username` VARCHAR(255) NOT NULL UNIQUE, `password` VARCHAR(255) NOT NULL, `role` TEXT DEFAULT 'professional', `createdAt` DATETIME NOT NULL, `updatedAt` DATETIME NOT NULL, `color` VARCHAR(255) NOT NULL DEFAULT '#b9d3fd');
